package com.example.userapp.network;

import java.util.concurrent.TimeUnit;
import okhttp3.OkHttpClient;
import okhttp3.logging.HttpLoggingInterceptor;

public class OkHttpProvider {

    private static OkHttpClient client;

    public static OkHttpClient getClient() {
        return getClient(null);
    }

    public static OkHttpClient getClient(AuthInterceptor.TokenProvider tokenProvider) {
        if (client == null) {
            synchronized (OkHttpProvider.class) {
                if (client == null) {
                    client = buildClient(tokenProvider);
                }
            }
        }
        return client;
    }

    private static OkHttpClient buildClient(AuthInterceptor.TokenProvider tokenProvider) {
        int timeout = EnvironmentConfig.getTimeoutSeconds();

        OkHttpClient.Builder builder = new OkHttpClient.Builder()
                .connectTimeout(timeout, TimeUnit.SECONDS)
                .readTimeout(timeout, TimeUnit.SECONDS)
                .writeTimeout(timeout, TimeUnit.SECONDS)
                .retryOnConnectionFailure(true);

        // Add auth interceptor
        if (tokenProvider != null) {
            builder.addInterceptor(new AuthInterceptor(tokenProvider));
        }

        // Add logging interceptor for non-production environments
        if (EnvironmentConfig.isLoggingEnabled()) {
            HttpLoggingInterceptor loggingInterceptor = new HttpLoggingInterceptor();
            loggingInterceptor.setLevel(HttpLoggingInterceptor.Level.BODY);
            builder.addInterceptor(loggingInterceptor);
        }

        return builder.build();
    }

    // Allow reset for testing or environment switching
    public static void reset() {
        synchronized (OkHttpProvider.class) {
            client = null;
        }
    }
}


