package com.example.userapp.network;

import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class RetrofitClient {

    private static Retrofit retrofit;
    private static ApiService apiService;

    public static Retrofit getRetrofit() {
        return getRetrofit(null);
    }

    public static Retrofit getRetrofit(AuthInterceptor.TokenProvider tokenProvider) {
        if (retrofit == null) {
            synchronized (RetrofitClient.class) {
                if (retrofit == null) {
                    retrofit = new Retrofit.Builder()
                            .baseUrl(EnvironmentConfig.getBaseUrl())
                            .client(OkHttpProvider.getClient(tokenProvider))
                            .addConverterFactory(GsonConverterFactory.create())
                            .build();
                }
            }
        }
        return retrofit;
    }

    public static ApiService getApiService() {
        return getApiService(null);
    }

    public static ApiService getApiService(AuthInterceptor.TokenProvider tokenProvider) {
        if (apiService == null) {
            synchronized (RetrofitClient.class) {
                if (apiService == null) {
                    apiService = getRetrofit(tokenProvider).create(ApiService.class);
                }
            }
        }
        return apiService;
    }

    // Allow reset for testing or environment switching
    public static void reset() {
        synchronized (RetrofitClient.class) {
            retrofit = null;
            apiService = null;
        }
        OkHttpProvider.reset();
    }
}


