package com.example.userapp.repository;

import android.util.Log;

import com.example.userapp.model.ApiResponse;
import com.example.userapp.model.Resource;
import com.example.userapp.model.User;
import com.example.userapp.network.ApiService;
import com.example.userapp.network.RetrofitClient;

import java.util.List;

import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;
import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;

public class UserRepository {

    private static final String TAG = "UserRepository";
    private final ApiService apiService;

    public UserRepository() {
        this.apiService = RetrofitClient.getApiService();
    }

    public UserRepository(ApiService apiService) {
        this.apiService = apiService;
    }

    public LiveData<Resource<List<User>>> getUsers() {
        MutableLiveData<Resource<List<User>>> usersLiveData = new MutableLiveData<>();
        usersLiveData.setValue(Resource.loading(null));

        apiService.getUsers().enqueue(new Callback<ApiResponse<List<User>>>() {
            @Override
            public void onResponse(Call<ApiResponse<List<User>>> call, Response<ApiResponse<List<User>>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    ApiResponse<List<User>> apiResponse = response.body();
                    if (apiResponse.isSuccess()) {
                        usersLiveData.postValue(Resource.success(apiResponse.getData()));
                    } else {
                        usersLiveData.postValue(Resource.error(
                                apiResponse.getMessage() != null ? apiResponse.getMessage() : "Unknown API error",
                                null
                        ));
                    }
                } else {
                    usersLiveData.postValue(Resource.error(
                            "Server error: " + response.code(),
                            null
                    ));
                }
            }

            @Override
            public void onFailure(Call<ApiResponse<List<User>>> call, Throwable t) {
                Log.e(TAG, "Failed to fetch users", t);
                usersLiveData.postValue(Resource.error(
                        "Network error: " + t.getMessage(),
                        null
                ));
            }
        });

        return usersLiveData;
    }

    public LiveData<Resource<List<User>>> getUsers(int page, int limit) {
        MutableLiveData<Resource<List<User>>> usersLiveData = new MutableLiveData<>();
        usersLiveData.setValue(Resource.loading(null));

        apiService.getUsers(page, limit).enqueue(new Callback<ApiResponse<List<User>>>() {
            @Override
            public void onResponse(Call<ApiResponse<List<User>>> call, Response<ApiResponse<List<User>>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    ApiResponse<List<User>> apiResponse = response.body();
                    if (apiResponse.isSuccess()) {
                        usersLiveData.postValue(Resource.success(apiResponse.getData()));
                    } else {
                        usersLiveData.postValue(Resource.error(
                                apiResponse.getMessage() != null ? apiResponse.getMessage() : "Unknown API error",
                                null
                        ));
                    }
                } else {
                    usersLiveData.postValue(Resource.error(
                            "Server error: " + response.code(),
                            null
                    ));
                }
            }

            @Override
            public void onFailure(Call<ApiResponse<List<User>>> call, Throwable t) {
                Log.e(TAG, "Failed to fetch users", t);
                usersLiveData.postValue(Resource.error(
                        "Network error: " + t.getMessage(),
                        null
                ));
            }
        });

        return usersLiveData;
    }

    public LiveData<Resource<User>> getUserById(long userId) {
        MutableLiveData<Resource<User>> userLiveData = new MutableLiveData<>();
        userLiveData.setValue(Resource.loading(null));

        apiService.getUserById(userId).enqueue(new Callback<ApiResponse<User>>() {
            @Override
            public void onResponse(Call<ApiResponse<User>> call, Response<ApiResponse<User>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    ApiResponse<User> apiResponse = response.body();
                    if (apiResponse.isSuccess()) {
                        userLiveData.postValue(Resource.success(apiResponse.getData()));
                    } else {
                        userLiveData.postValue(Resource.error(
                                apiResponse.getMessage() != null ? apiResponse.getMessage() : "User not found",
                                null
                        ));
                    }
                } else {
                    userLiveData.postValue(Resource.error(
                            "Server error: " + response.code(),
                            null
                    ));
                }
            }

            @Override
            public void onFailure(Call<ApiResponse<User>> call, Throwable t) {
                Log.e(TAG, "Failed to fetch user by id: " + userId, t);
                userLiveData.postValue(Resource.error(
                        "Network error: " + t.getMessage(),
                        null
                ));
            }
        });

        return userLiveData;
    }

    public LiveData<Resource<User>> createUser(User user) {
        MutableLiveData<Resource<User>> resultLiveData = new MutableLiveData<>();
        resultLiveData.setValue(Resource.loading(null));

        apiService.createUser(user).enqueue(new Callback<ApiResponse<User>>() {
            @Override
            public void onResponse(Call<ApiResponse<User>> call, Response<ApiResponse<User>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    ApiResponse<User> apiResponse = response.body();
                    if (apiResponse.isSuccess()) {
                        resultLiveData.postValue(Resource.success(apiResponse.getData()));
                    } else {
                        resultLiveData.postValue(Resource.error(
                                apiResponse.getMessage() != null ? apiResponse.getMessage() : "Failed to create user",
                                null
                        ));
                    }
                } else {
                    resultLiveData.postValue(Resource.error(
                            "Server error: " + response.code(),
                            null
                    ));
                }
            }

            @Override
            public void onFailure(Call<ApiResponse<User>> call, Throwable t) {
                Log.e(TAG, "Failed to create user", t);
                resultLiveData.postValue(Resource.error(
                        "Network error: " + t.getMessage(),
                        null
                ));
            }
        });

        return resultLiveData;
    }
}


