package com.example.userapp.viewmodel;

import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.lifecycle.ViewModel;

import com.example.userapp.model.Resource;
import com.example.userapp.model.User;
import com.example.userapp.repository.UserRepository;

import java.util.List;

public class UserViewModel extends ViewModel {

    private final UserRepository userRepository;
    private LiveData<Resource<List<User>>> usersLiveData;
    private LiveData<Resource<User>> selectedUserLiveData;

    public UserViewModel() {
        this.userRepository = new UserRepository();
    }

    public UserViewModel(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    public LiveData<Resource<List<User>>> getUsers() {
        if (usersLiveData == null) {
            usersLiveData = userRepository.getUsers();
        }
        return usersLiveData;
    }

    public LiveData<Resource<List<User>>> refreshUsers() {
        usersLiveData = userRepository.getUsers();
        return usersLiveData;
    }

    public LiveData<Resource<List<User>>> getUsers(int page, int limit) {
        return userRepository.getUsers(page, limit);
    }

    public LiveData<Resource<User>> getUserById(long userId) {
        selectedUserLiveData = userRepository.getUserById(userId);
        return selectedUserLiveData;
    }

    public LiveData<Resource<User>> createUser(User user) {
        return userRepository.createUser(user);
    }
}


