package com.example.userapp;

import android.app.Application;

import com.example.userapp.network.EnvironmentConfig;

public class UserApp extends Application {

    @Override
    public void onCreate() {
        super.onCreate();
        initEnvironment();
    }

    private void initEnvironment() {
        // The environment is determined by the build flavor.
        // BuildConfig.BASE_URL is set per product flavor in build.gradle.
        // Here we map it to our EnvironmentConfig enum.

        // Using BuildConfig values set by product flavors:
        // String baseUrl = BuildConfig.BASE_URL;
        // boolean enableLogging = BuildConfig.ENABLE_LOGGING;

        // For simplicity in MVP, detect based on BuildConfig.BUILD_TYPE and FLAVOR
        // Uncomment and adjust based on your actual BuildConfig:
        /*
        if (BuildConfig.FLAVOR.equals("production")) {
            EnvironmentConfig.init(EnvironmentConfig.Environment.PRODUCTION);
        } else if (BuildConfig.FLAVOR.equals("staging")) {
            EnvironmentConfig.init(EnvironmentConfig.Environment.STAGING);
        } else {
            EnvironmentConfig.init(EnvironmentConfig.Environment.DEVELOPMENT);
        }
        */

        // Default for MVP - switch as needed
        EnvironmentConfig.init(EnvironmentConfig.Environment.DEVELOPMENT);
    }
}


